// ─── GLOBAL STYLES ────────────────────────────────────────────────────────────
const G = `
@import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,600;1,300;1,400;1,600&family=Jost:wght@300;400;500;600&display=swap');
:root{
  --cr:#F5EDE3; --cw:#FBF7F2; --cb:#2C1A0E; --cbt:#7A4E2D; --ct:#8B6343;
  --cs:#5C7A5A; --csg:#E8F0E8; --cg:#D4C5B0; --ca:#C4895A;
}
*{box-sizing:border-box;margin:0;padding:0;}
html{scroll-behavior:smooth;}
body{font-family:'Jost',sans-serif;background:var(--cw);color:var(--cb);overflow-x:hidden;}
.serif{font-family:'Cormorant Garamond',serif;}
.reveal{opacity:0;transform:translateY(28px);transition:opacity .75s cubic-bezier(.16,1,.3,1),transform .75s cubic-bezier(.16,1,.3,1);}
.reveal.in{opacity:1;transform:translateY(0);}
.reveal-l{opacity:0;transform:translateX(-28px);transition:opacity .75s cubic-bezier(.16,1,.3,1),transform .75s cubic-bezier(.16,1,.3,1);}
.reveal-l.in{opacity:1;transform:translateX(0);}
.reveal-r{opacity:0;transform:translateX(28px);transition:opacity .75s cubic-bezier(.16,1,.3,1),transform .75s cubic-bezier(.16,1,.3,1);}
.reveal-r.in{opacity:1;transform:translateX(0);}
@keyframes drift{0%,100%{transform:translateY(0) rotate(0deg);}50%{transform:translateY(-10px) rotate(1deg);}}
.nav-link{position:relative;text-decoration:none;font-size:12px;font-weight:500;letter-spacing:.13em;text-transform:uppercase;color:var(--cb);opacity:.6;transition:opacity .2s;}
.nav-link::after{content:'';position:absolute;bottom:-2px;left:0;width:100%;height:1px;background:var(--ca);transform:scaleX(0);transform-origin:left;transition:transform .3s cubic-bezier(.16,1,.3,1);}
.nav-link:hover{opacity:1;} .nav-link:hover::after{transform:scaleX(1);}
.nav-link.active{opacity:1;} .nav-link.active::after{transform:scaleX(1);}
.btn-p{display:inline-flex;align-items:center;gap:9px;background:var(--cb);color:var(--cr);border:none;border-radius:2px;padding:15px 32px;font-family:'Jost',sans-serif;font-size:12px;font-weight:500;letter-spacing:.15em;text-transform:uppercase;cursor:pointer;transition:all .3s;position:relative;overflow:hidden;}
.btn-p::before{content:'';position:absolute;inset:0;background:var(--cbt);transform:translateX(-101%);transition:transform .4s cubic-bezier(.16,1,.3,1);}
.btn-p:hover::before{transform:translateX(0);}
.btn-p span{position:relative;z-index:1;}
.btn-o{display:inline-flex;align-items:center;gap:9px;background:transparent;color:var(--cb);border:1px solid rgba(44,26,14,.28);border-radius:2px;padding:14px 32px;font-family:'Jost',sans-serif;font-size:12px;font-weight:500;letter-spacing:.15em;text-transform:uppercase;cursor:pointer;transition:all .3s;}
.btn-o:hover{border-color:var(--cb);background:rgba(44,26,14,.04);}
.pill{display:inline-flex;align-items:center;gap:6px;background:var(--csg);color:var(--cs);border-radius:20px;padding:5px 13px;font-size:11px;font-weight:500;letter-spacing:.08em;text-transform:uppercase;}
.pcard{background:var(--cr);border-radius:4px;overflow:hidden;transition:transform .4s cubic-bezier(.16,1,.3,1),box-shadow .4s;}
.pcard:hover{transform:translateY(-5px);box-shadow:0 18px 56px rgba(44,26,14,.11);}
.pcard:hover .pci{transform:scale(1.02);}
.pci{transition:transform .6s cubic-bezier(.16,1,.3,1);overflow:hidden;}
.ifield{width:100%;background:var(--cr);border:1px solid rgba(44,26,14,.12);border-radius:2px;padding:13px 16px;font-family:'Jost',sans-serif;font-size:14px;color:var(--cb);outline:none;transition:border-color .3s;}
.ifield:focus{border-color:var(--ca);}
.ifield::placeholder{color:rgba(44,26,14,.32);}
.swatch{width:28px;height:28px;border-radius:50%;cursor:pointer;transition:transform .2s,box-shadow .2s;border:2px solid transparent;}
.swatch:hover{transform:scale(1.15);}
.swatch.sel{box-shadow:0 0 0 2px var(--cr),0 0 0 4px var(--cb);}
.bcard{background:var(--cw);border:1px solid rgba(44,26,14,.08);border-radius:6px;overflow:hidden;transition:border-color .3s,box-shadow .3s;}
.bcard:hover{border-color:rgba(196,137,90,.35);box-shadow:0 6px 28px rgba(196,137,90,.09);}
.bcard.selected{border-color:var(--ca);box-shadow:0 0 0 1px var(--ca);}
.qty-btn{width:32px;height:32px;border:1px solid rgba(44,26,14,.18);background:none;border-radius:2px;cursor:pointer;font-family:'Jost',sans-serif;font-size:16px;color:var(--cb);transition:background .2s;display:flex;align-items:center;justify-content:center;}
.qty-btn:hover{background:var(--cr);}
.pre-card{background:var(--cr);border-radius:6px;padding:32px;border:1px solid rgba(44,26,14,.06);}
.tab-btn{padding:10px 24px;background:none;border:1px solid rgba(44,26,14,.15);border-radius:2px;cursor:pointer;font-family:'Jost',sans-serif;font-size:12px;font-weight:500;letter-spacing:.12em;text-transform:uppercase;color:var(--ct);transition:all .25s;}
.tab-btn.active{background:var(--cb);color:var(--cr);border-color:var(--cb);}
`;

