function IllustFiber() {
  return (
    <svg viewBox="0 0 320 320" width="320" height="320" xmlns="http://www.w3.org/2000/svg">
      {/* Woven fiber texture pattern — warm terracotta tones */}
      {[0,1,2,3,4,5,6,7].map(row =>
        [0,1,2,3,4,5,6,7].map(col => (
          <rect key={`${row}-${col}`}
            x={col * 40 + (row % 2 === 0 ? 0 : 20)}
            y={row * 40}
            width="38" height="38" rx="3"
            fill={(row + col) % 3 === 0 ? "#B87040" : (row + col) % 3 === 1 ? "#C4895A" : "#D4956A"}
            opacity={0.7 + (row * col % 3) * 0.1}
          />
        ))
      )}
      {/* Vertical fiber strands */}
      {[20,60,100,140,180,220,260,300].map(x => (
        <rect key={x} x={x - 2} y="0" width="4" height="320" rx="2" fill="#8B5E3C" opacity=".3"/>
      ))}
      {/* Horizontal fiber strands */}
      {[20,60,100,140,180,220,260,300].map(y => (
        <rect key={y} x="0" y={y - 2} width="320" height="4" rx="2" fill="#7A4E2D" opacity=".25"/>
      ))}
      {/* Center overlay circle with label */}
      <circle cx="160" cy="160" r="72" fill="#2C1A0E" opacity=".55"/>
      <text x="160" y="153" textAnchor="middle" fill="#F5EDE3" fontSize="13" fontFamily="Georgia,serif" fontWeight="400" letterSpacing="3">BANANA</text>
      <text x="160" y="170" textAnchor="middle" fill="#C4895A" fontSize="11" fontFamily="Georgia,serif" fontStyle="italic">Sheath Fiber</text>
      <text x="160" y="185" textAnchor="middle" fill="#F5EDE3" fontSize="10" fontFamily="sans-serif" letterSpacing="2" opacity=".6">BIO-LEATHER</text>
    </svg>
  );
}

